import React, { useState, useEffect } from 'react';
import './Matrix.css';

const Matrix = () => {
  // Declare state variables for rows and columns
  const [rows, setRows] = useState(5);
  const [columns, setColumns] = useState(5);

  // Declare state variable for grid
  const [grid, setGrid] = useState([]);

  // Initialize grid state to all 0s
  useEffect(() => {
    let newGrid = [];
    for (let i = 0; i < rows; i++) {
      let row = [];
      for (let j = 0; j < columns; j++) {
        row.push(0);
      }
      newGrid.push(row);
    }
    setGrid(newGrid);
  }, [rows, columns]);

  // Function to handle box click
  const handleBoxClick = (row, col) => {
    // Copy current grid state
    let newGrid = [...grid];
    // Toggle the box value between 0 and 1
    newGrid[row][col] = newGrid[row][col] === 0 ? 1 : 0;
    // Update grid state
    setGrid(newGrid);
  };

  // Render matrix
  const renderMatrix = () => {
    let matrix = [];
    for (let i = 0; i < rows; i++) {
      let row = [];
      for (let j = 0; j < columns; j++) {
        if (grid[i] && grid[i][j] !== undefined) {
          row.push(
            <div
              className="grid-square"
              style={{ backgroundColor: grid[i][j] === 0 ? "white" : "black" }}
              onClick={() => handleBoxClick(i, j)}
              key={`${i}-${j}`}
            />
          );
        }
      }
      matrix.push(<div className="grid-row" style={{ display: 'flex', flexDirection: 'column' }} key={i}>{row}</div>);
    }
    return matrix;


  };

  return (
    <div className="nonogram-container">
        <h1>Nonogram Puzzle Game</h1>
      <div className="input-container">
        <label>Rows:</label>
        <input type="number" value={rows} onChange={e => setRows(parseInt(e.target.value, 10))} />
        <label>Columns:</label>
        <input type="number" value={columns} onChange={e => setColumns(parseInt(e.target.value, 10))} />
      </div>
      <div className="grid-container">{renderMatrix()}</div>
    </div>
  );
};

export default Matrix;



























